21	var loadRoutingCatalog = modelcatalog.Default
22	
23	// ResolveRoute resolves an under-specified RouteRequest to a concrete
24	// (Harness, Provider, Model) decision per CONTRACT-003.
25	//
26	// The implementation delegates to internal/routing.Resolve — the single
27	// routing engine that consolidates DDx-side harness-tier ranking and
28	// fiz-side provider failover ordering.
29	func (s *service) ResolveRoute(ctx context.Context, req RouteRequest) (*RouteDecision, error) {
30		if err := ValidatePowerBounds(req.MinPower, req.MaxPower); err != nil {
31			return nil, err
32		}
33		if err := ValidateRole(req.Role); err != nil {
34			return nil, err
35		}
36		if err := ValidateCorrelationID(req.CorrelationID); err != nil {
37			return nil, err
38		}
39		if req.Harness != "" && req.Model != "" {
40			canonical := harnesses.ResolveHarnessAlias(req.Harness)
41			if !s.registry.Has(canonical) {
42				return nil, fmt.Errorf("unknown harness %q", req.Harness)
43			}
44			cfg, _ := s.registry.Get(canonical)
45			if err := validateExplicitHarnessModel(canonical, cfg, req.Model, req.Provider); err != nil {
46				return nil, err
47			}
48		}
49		if req.Harness != "" && req.Policy != "" {
50			canonical := harnesses.ResolveHarnessAlias(req.Harness)
51			if !s.registry.Has(canonical) {
52				return nil, fmt.Errorf("unknown harness %q", req.Harness)
53			}
54			cfg, _ := s.registry.Get(canonical)
55			if err := validateExplicitHarnessPolicy(canonical, cfg, req.Policy); err != nil {
56				return nil, err
57			}
58		}
59		cat := serviceRoutingCatalog()
60		requestedPolicy := req.Policy
61		policy := routingPolicyForName(cat, requestedPolicy)
62		powerPolicy := routePowerPolicyForRequest(cat, req)
63		providerPreference, err := providerPreferenceForPolicy(cat, requestedPolicy)
64		if err != nil {
65			return &RouteDecision{
66				RequestedPolicy: req.Policy,
67				PowerPolicy:     powerPolicy,
68			}, err
69		}
70		in, snapshot := s.buildRoutingInputsWithCatalog(ctx, cat, modelsnapshot.RefreshNone)
71	
72		resolvedModel, modelCandidates, modelErr := s.resolveModelConstraint(req.Harness, req.Provider, req.Model, in, cat)
73		if modelErr != nil {
74			result := &RouteDecision{
75				RequestedPolicy: req.Policy,
76				PowerPolicy:     powerPolicy,
77				Candidates:      modelCandidates,
78			}
79			s.annotateRouteDecisionEvidence(result)
80			return result, publicRoutingError(modelErr, result.Candidates, req.Policy)
81		}
82	
83		rReq := routing.Request{
84			Policy:                policy,
85			Model:                 resolvedModel,
86			Provider:              req.Provider,
87			Harness:               req.Harness,
88			Reasoning:             effectiveReasoningString(req.Reasoning),
89			Permissions:           req.Permissions,
90			ProviderPreference:    providerPreference,
91			EstimatedPromptTokens: req.EstimatedPromptTokens,
92			RequiresTools:         req.RequiresTools,
93			CorrelationID:         req.CorrelationID,
94			AllowLocal:            req.AllowLocal,
95			Require:               append([]string(nil), req.Require...),
96			ExcludedRoutes:        publicToRoutingExcludedRoutes(req.ExcludedRoutes),
97		}
98		if policyEntry, _, ok := policyForName(cat, requestedPolicy); ok {
99			rReq.AllowLocal = rReq.AllowLocal || policyEntry.AllowLocal
100			rReq.Require = append(append([]string(nil), policyEntry.Require...), rReq.Require...)
101		}
102		rReq.MinPower, rReq.MaxPower = routePowerBoundsForRequest(req, powerPolicy)
103		s.applyRouteAttemptCooldowns(&in)
104		dec, err := routing.Resolve(rReq, in)
105		if err != nil {
106			if escalated, edec, eerr := escalatePolicyLadder(rReq, in, err, req.Policy); escalated {
107				dec = edec
108				err = eerr
109			}
110		}
111		result := routeDecisionFromInternal(dec, powerPolicy)
112		if err != nil {
113			if result == nil {
114				result = &RouteDecision{}
115			}
116			result.RequestedPolicy = req.Policy
117			result.PowerPolicy = powerPolicy
118			s.annotateRouteDecisionEvidence(result)
119			return result, publicRoutingError(err, result.Candidates, req.Policy)
120		}
121		s.applyStickyRouteLease(req.CorrelationID, result)
122		if result != nil && result.Endpoint == "" {
123			_, endpoint, _ := splitEndpointProviderRef(result.Provider)
124			result.Endpoint = endpoint
125		}
126		s.annotateRouteDecisionSnapshotEvidence(result, snapshot)
127		s.annotateRouteDecisionEvidence(result)
128		// Cache the decision so RouteStatus can surface LastDecision.
129		if result != nil {
130			result.RequestedPolicy = req.Policy
131			result.PowerPolicy = powerPolicy
132			result.Model = resolveSubprocessModelAlias(result.Harness, result.Model)
133			result.Power = catalogPowerForModel(cat, result.Model)
134		}
135		s.cacheRouteDecision(req.Model, result)
136		return result, nil
137	}
