270	func routeSnapshotEvidenceForCandidate(candidate RouteCandidate, snapshot modelsnapshot.ModelSnapshot) (modelsnapshot.KnownModel, bool) {
271		index := routeSnapshotCandidateIndex(snapshot)
272		if len(index) == 0 {
273			return modelsnapshot.KnownModel{}, false
274		}
275		provider := strings.TrimSpace(candidate.Provider)
276		endpoint := strings.TrimSpace(candidate.Endpoint)
277		serverInstance := strings.TrimSpace(candidate.ServerInstance)
278		model := strings.TrimSpace(candidate.Model)
279		if base, ep, ok := splitEndpointProviderRef(provider); ok {
280			provider = base
281			if endpoint == "" {
282				endpoint = ep
283			}
284		}
285		keys := []routeSnapshotCandidateKey{{
286			Provider:       provider,
287			Endpoint:       endpoint,
288			ServerInstance: serverInstance,
289			Model:          model,
290		}}
291		if endpoint == "" {
292			keys = append(keys, routeSnapshotCandidateKey{
293				Provider:       provider,
294				ServerInstance: serverInstance,
295				Model:          model,
296			})
297		}
298		if serverInstance == "" {
299			keys = append(keys, routeSnapshotCandidateKey{
300				Provider: provider,
301				Endpoint: endpoint,
302				Model:    model,
303			})
304			if endpoint == "" {
305				keys = append(keys, routeSnapshotCandidateKey{
306					Provider: provider,
307					Model:    model,
308				})
309			}
310		}
311		for _, key := range keys {
312			if row, ok := index[key]; ok {
313				return row, true
314			}
315		}
316		for _, row := range snapshot.Models {
317			rowProvider := strings.TrimSpace(row.Provider)
318			rowEndpoint := strings.TrimSpace(row.EndpointName)
319			rowServerInstance := strings.TrimSpace(serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance))
320			if rowProvider != provider || strings.TrimSpace(row.ID) != model {
321				continue
322			}
323			if endpoint != "" && rowEndpoint != endpoint {
324				continue
325			}
326			if serverInstance != "" && rowServerInstance != serverInstance {
327				continue
328			}
329			return row, true
330		}
331		return modelsnapshot.KnownModel{}, false
332	}
