435	func routeUtilizationStateFromSample(sample utilization.EndpointUtilization) RouteUtilizationState {
436		out := RouteUtilizationState{
437			Source:     string(sample.Source),
438			Freshness:  string(sample.Freshness),
439			ObservedAt: sample.ObservedAt,
440		}
441		if sample.ActiveRequests != nil {
442			out.ActiveRequests = utilization.Int(*sample.ActiveRequests)
443		}
444		if sample.QueuedRequests != nil {
445			out.QueuedRequests = utilization.Int(*sample.QueuedRequests)
446		}
447		if sample.MaxConcurrency != nil {
448			out.MaxConcurrency = utilization.Int(*sample.MaxConcurrency)
449		}
450		if sample.CacheUsage != nil {
451			v := *sample.CacheUsage
452			out.CachePressure = &v
453		}
454		if out.CachePressure == nil && sample.MaxConcurrency != nil && *sample.MaxConcurrency > 0 {
455			total := 0
456			if sample.ActiveRequests != nil {
457				total += *sample.ActiveRequests
458			}
459			if sample.QueuedRequests != nil {
460				total += *sample.QueuedRequests
461			}
462			pressure := float64(total) / float64(*sample.MaxConcurrency)
463			out.CachePressure = &pressure
464		}
465		return out
466	}
