686	func (s *service) routeAttemptTTL() time.Duration {
687		if s.opts.ServiceConfig == nil {
688			return defaultRouteAttemptCooldown
689		}
690		ttl := s.opts.ServiceConfig.HealthCooldown()
691		if ttl <= 0 {
692			return defaultRouteAttemptCooldown
693		}
694		return ttl
695	}
