1036	func snapshotEndpointName(pcfg ServiceProviderEntry, key snapshotProviderGroupKey) string {
1037		endpoints := modelDiscoveryEndpoints(pcfg)
1038		trimmedEndpointName := strings.TrimSpace(key.EndpointName)
1039		trimmedBaseURL := strings.TrimSpace(key.EndpointBaseURL)
1040		trimmedServerInstance := strings.TrimSpace(key.ServerInstance)
1041		if len(endpoints) == 0 {
1042			if trimmedEndpointName != "" {
1043				if strings.EqualFold(trimmedEndpointName, strings.TrimSpace(key.Provider)) {
1044					return "default"
1045				}
1046				return trimmedEndpointName
1047			}
1048			if trimmedServerInstance != "" {
1049				return trimmedServerInstance
1050			}
1051			if trimmedBaseURL != "" {
1052				return trimmedBaseURL
1053			}
1054			return ""
1055		}
1056		for _, endpoint := range endpoints {
1057			if trimmedEndpointName != "" && strings.EqualFold(endpoint.Name, trimmedEndpointName) {
1058				return endpoint.Name
1059			}
1060			if trimmedBaseURL != "" && strings.TrimSpace(endpoint.BaseURL) == trimmedBaseURL {
1061				return endpoint.Name
1062			}
1063			if trimmedServerInstance != "" && strings.TrimSpace(endpoint.ServerInstance) == trimmedServerInstance {
1064				return endpoint.Name
1065			}
1066		}
1067		if len(endpoints) == 1 {
1068			return endpoints[0].Name
1069		}
1070		if trimmedEndpointName != "" {
1071			return trimmedEndpointName
1072		}
1073		if trimmedServerInstance != "" {
1074			return trimmedServerInstance
1075		}
1076		if trimmedBaseURL != "" {
1077			return trimmedBaseURL
1078		}
1079		return ""
1080	}
