1476	// DefaultModel and any DiscoveredIDs) with no_tools=true.
1477	func providerSupportsTools(cat *modelcatalog.Catalog, defaultModel string, discoveredIDs []string) bool {
1478		if cat == nil {
1479			return true
1480		}
1481		checked := false
1482		if defaultModel != "" {
1483			if cat.SupportsToolsForModel(defaultModel) {
1484				return true
1485			}
1486			checked = true
1487		}
1488		for _, id := range discoveredIDs {
1489			if id == "" {
1490				continue
1491			}
1492			if cat.SupportsToolsForModel(id) {
1493				return true
1494			}
1495			checked = true
1496		}
1497		if !checked {
1498			return true
1499		}
1500		return false
1501	}
