1624			modelcatalog.SurfaceGemini,
1625		} {
1626			resolved, err := cat.Resolve(ref, modelcatalog.ResolveOptions{
1627				Surface:         surface,
1628				AllowDeprecated: true,
1629			})
1630			if err == nil && resolved.ConcreteModel != "" {
1631				return resolved.ConcreteModel
1632			}
1633		}
1634		return ""
