1637	func (s *service) subscriptionCostCurve() SubscriptionCostCurve {
1638		if s.opts.SubscriptionCostCurve == nil {
1639			return defaultSubscriptionCostCurve()
1640		}
1641		curve := *s.opts.SubscriptionCostCurve
1642		def := defaultSubscriptionCostCurve()
1643		if curve.FreeUntilPercent == 0 {
1644			curve.FreeUntilPercent = def.FreeUntilPercent
1645		}
1646		if curve.LowUntilPercent == 0 {
1647			curve.LowUntilPercent = def.LowUntilPercent
1648		}
1649		if curve.MediumUntilPercent == 0 {
1650			curve.MediumUntilPercent = def.MediumUntilPercent
1651		}
1652		if curve.LowMultiplier == 0 {
1653			curve.LowMultiplier = def.LowMultiplier
1654		}
1655		if curve.MediumMultiplier == 0 {
1656			curve.MediumMultiplier = def.MediumMultiplier
1657		}
1658		if curve.HighMultiplier == 0 {
1659			curve.HighMultiplier = def.HighMultiplier
1660		}
1661		return curve
1662	}
1663	
1664	func defaultSubscriptionCostCurve() SubscriptionCostCurve {
1665		return SubscriptionCostCurve{
1666			FreeUntilPercent:   70,
1667			LowUntilPercent:    80,
1668			MediumUntilPercent: 90,
1669			LowMultiplier:      0.1,
1670			MediumMultiplier:   0.3,
1671			HighMultiplier:     1.2,
1672		}
1673	}
1674	
1675	func subscriptionEffectiveCostUSDPer1kTokens(baseCost float64, quotaPercentUsed int, curve SubscriptionCostCurve) float64 {
1676		switch {
1677		case quotaPercentUsed <= curve.FreeUntilPercent:
1678			return 0
1679		case quotaPercentUsed <= curve.LowUntilPercent:
1680			return baseCost * curve.LowMultiplier
1681		case quotaPercentUsed <= curve.MediumUntilPercent:
1682			return baseCost * curve.MediumMultiplier
1683		default:
1684			return baseCost * curve.HighMultiplier
1685		}
1686	}
