1742	func routePowerPolicyForRequest(cat *modelcatalog.Catalog, req RouteRequest) RoutePowerPolicy {
1743		policy := RoutePowerPolicy{
1744			PolicyName: req.Policy,
1745			MinPower:   req.MinPower,
1746			MaxPower:   req.MaxPower,
1747		}
1748		if req.Policy == "" || cat == nil {
1749			return policy
1750		}
1751		policyEntry, policyName, ok := policyForName(cat, req.Policy)
1752		if !ok {
1753			return policy
1754		}
1755		policy.PolicyName = policyName
1756		if policyEntry.MinPower > 0 {
1757			if policy.MinPower == 0 || policyEntry.MinPower > policy.MinPower {
1758				policy.MinPower = policyEntry.MinPower
1759			}
1760		}
1761		if policyEntry.MaxPower > 0 {
1762			if policy.MaxPower == 0 || policyEntry.MaxPower < policy.MaxPower {
1763				policy.MaxPower = policyEntry.MaxPower
1764			}
1765		}
1766		return policy
1767	}
1768	
1769	func routePowerBoundsForRequest(req RouteRequest, policy RoutePowerPolicy) (int, int) {
1770		// Exact model pins remain exact model identity pins. The policy still
1771		// reports its effective power policy for evidence, but it does not widen
1772		// or override the caller's model.
1773		if req.Model != "" {
1774			return req.MinPower, req.MaxPower
1775		}
1776		return policy.MinPower, policy.MaxPower
1777	}
