3	// costClassRank maps cost class to numeric rank (lower = cheaper).
4	var costClassRank = map[string]int{
5		"local":        0,
6		"cheap":        1,
7		"medium":       2,
8		"expensive":    3,
9		"experimental": -1,
10		"":             2, // unknown = medium
11	}
12	
13	const StickyAffinityBonus = 250.0
14	const unknownUtilizationPenalty = 5.0
15	const unknownPerformancePenalty = 5.0
16	const belowMinPowerPenalty = 12.0
17	
18	// scorePolicy returns a score for a candidate under the named policy.
19	// Higher is better.
20	//
21	// Routing priority policy (ported from DDx routing.go):
22	//   - cheap: local + low-cost preferred; subscription-within-quota next.
23	//   - default: balanced; light local/subscription preference to avoid spend.
24	//   - smart: quality first; cloud capability wins; no local bonus.
25	//
26	// The policy is policy-aware AND provider-aware via providerBias hooks
27	// supplied by the caller (cooldown demotion, observation perf bias,
28	// provider-affinity bias).
29	func scorePolicy(policy string, cand candidateInternal) float64 {
30		total := 0.0
31		for _, component := range scoreComponents(policy, cand) {
32			total += component
33		}
34		return total
35	}
36	
37	func scoreComponents(policy string, cand candidateInternal) map[string]float64 {
38		components := map[string]float64{
39			"base":                100,
40			"cost":                0,
41			"deployment_locality": 0,
42			"quota_health":        0,
43			"utilization":         0,
44			"performance":         0,
45			"power":               0,
46			"context_headroom":    0,
47			"sticky_affinity":     0,
48		}
49		base := 100.0
50		cr := costClassRank[cand.CostClass]
51		withinQuota := cand.IsSubscription && cand.QuotaOK
52		hasPowerBounds := cand.MinPower > 0 || cand.MaxPower > 0
53		add := func(name string, value float64) {
54			if value == 0 {
55				return
56			}
57			components[name] += value
58		}
59	
60		// Policy preference scoring. When no power bounds are set the full policy
61		// block applies (original behavior). When power bounds are set, apply only
62		// the subscription/quota bonus to in-bounds candidates so that a free
63		// subscription candidate still beats a metered one among the eligible set.
64		// Locality bonuses and cost-class rank penalties remain gated on
65		// !hasPowerBounds: locality bonuses would otherwise let metered providers
66		// that inherit a "local" cost class from their harness outrank subscription
67		// candidates, and cost penalties would double-penalize metered candidates.
68		switch policy {
69		case "cheap":
70			if !hasPowerBounds {
71				if cand.CostClass == "local" {
72					base += 40
73					add("deployment_locality", 40)
74				} else if withinQuota {
75					base += 20
76					add("quota_health", 20)
77				}
78				base -= float64(cr) * 30
79				add("cost", -float64(cr)*30)
80			} else if candidateWithinPowerBounds(cand) && withinQuota {
81				base += 20
82				add("quota_health", 20)
83			}
84	
85		case "default":
86			if !hasPowerBounds {
87				if cand.CostClass == "local" {
88					base += 25
89					add("deployment_locality", 25)
90				} else if withinQuota {
91					base += 15
92					add("quota_health", 15)
93				}
94				base -= float64(cr) * 10
95				add("cost", -float64(cr)*10)
96			} else if candidateWithinPowerBounds(cand) && withinQuota {
97				base += 15
98				add("quota_health", 15)
99			}
100	
101		case "smart":
102			if !hasPowerBounds {
103				// Quality first; higher cost rank approximates higher capability.
104				base += float64(cr) * 20
105				add("cost", float64(cr)*20)
106				if withinQuota {
107					base += 5
108					add("quota_health", 5)
109				}
110			} else if candidateWithinPowerBounds(cand) && withinQuota {
111				base += 5
112				add("quota_health", 5)
113			}
114	
115		default:
116			// Treat unspecified as default.
117			if !hasPowerBounds {
118				if cand.CostClass == "local" {
119					base += 25
120					add("deployment_locality", 25)
121				} else if withinQuota {
122					base += 15
123					add("quota_health", 15)
124				}
125				base -= float64(cr) * 10
126				add("cost", -float64(cr)*10)
127			} else if candidateWithinPowerBounds(cand) && withinQuota {
128				base += 15
129				add("quota_health", 15)
130			}
131		}
132	
133		// Provider preference bias. When power bounds are set, apply only the
134		// subscription-first preference to in-bounds subscription candidates; the
135		// local-first bias is omitted for the same locality-inheritance reason as
136		// the policy locality bonuses above.
137		if !hasPowerBounds {
138			switch cand.ProviderPreference {
139			case "local-first", "":
140				if cand.CostClass == "local" {
141					base += 30
142					add("deployment_locality", 30)
143				}
144			case "subscription-first":
145				if cand.IsSubscription && cand.QuotaOK {
146					base += 30
147					add("quota_health", 30)
148				}
149			}
150		} else if candidateWithinPowerBounds(cand) && cand.ProviderPreference == "subscription-first" && cand.IsSubscription && cand.QuotaOK {
151			base += 30
152			add("quota_health", 30)
153		}
154	
155		// Quota signals.
156		if cand.IsSubscription {
157			// Stale quota penalty.
158			if cand.QuotaStale {
159				base -= 15
160				add("quota_health", -15)
161			}
162	
163			// Trend-based adjustments.
164			switch cand.QuotaTrend {
165			case "exhausting":
166				base -= 40
167				add("quota_health", -40)
168			case "burning":
169				base -= 20
170				add("quota_health", -20)
171			case "healthy":
172				base += 10
173				add("quota_health", 10)
174			}
175	
176			// Continuous quota pressure: subscription harnesses should start
177			// yielding before they are nearly exhausted, with steeper demotion
178			// once headroom drops below 50% and again below 20%.
179			if cand.QuotaPercentUsed > 0 {
180				penalty := quotaPressurePenalty(cand.QuotaPercentUsed)
181				base -= penalty
182				add("quota_health", -penalty)
183			}
184		}
185	
186		// Historical success-rate adjustment (only when sufficient samples).
187		if cand.HistoricalSuccessRate >= 0 {
188			switch {
189			case cand.HistoricalSuccessRate >= 0.8:
190				base += 20
191				add("quota_health", 20)
192			case cand.HistoricalSuccessRate < 0.5:
193				base -= 30
194				add("quota_health", -30)
195			}
196		}
197		if cand.ProviderSuccessRate >= 0 {
198			switch {
199			case cand.ProviderSuccessRate >= 0.8:
200				base += 25
201				add("quota_health", 25)
202			case cand.ProviderSuccessRate < 0.5:
203				base -= 35
204				add("quota_health", -35)
205			}
206		}
207	
208		// Cooldown demotion: candidate has had recent failures.
209		if cand.InCooldown {
210			base -= 50
211			add("quota_health", -50)
212		}
213	
214		// Sticky affinity is a bonus after eligibility, not a hard pin.
215		if cand.StickyMatch {
216			base += StickyAffinityBonus
217			add("sticky_affinity", StickyAffinityBonus)
218		}
219	
220		// Utilization pressure can outweigh stickiness when the chosen server is
221		// already busy or saturated.
222		// Unknown or stale utilization is treated explicitly. Missing data gets a
223		// small penalty so it cannot outrank a peer with real healthy evidence by
224		// accident.
225		if cand.EndpointSaturated {
226			base -= 300
227			add("utilization", -300)
228		}
229		if cand.EndpointLoad > 0 {
230			loadPenalty := cand.EndpointLoad * 10
231			if cand.EndpointLoadFresh {
232				loadPenalty *= 2
233			} else {
234				loadPenalty += unknownUtilizationPenalty
235			}
236			if loadPenalty > 60 {
237				loadPenalty = 60
238			}
239			base -= loadPenalty
240			add("utilization", -loadPenalty)
241		} else if !cand.EndpointLoadFresh {
242			base -= unknownUtilizationPenalty
243			add("utilization", -unknownUtilizationPenalty)
244		}
245	
246		// Provider affinity: explicit provider pins are filtered before scoring;
247		// this bonus only affects the ordering among still-eligible candidates
248		// that share the pinned provider identity.
249		if cand.ProviderAffinityMatch {
250			base += 15
251			add("deployment_locality", 15)
252		}
253	
254		if cand.Power > 0 && cand.MinPower == 0 && cand.MaxPower == 0 {
255			base += float64(cand.Power) * 12
256			add("power", float64(cand.Power)*12)
257		}
258		if cand.Power > 0 {
259			if cand.MinPower > 0 && cand.Power < cand.MinPower {
260				// Below-min candidates need a materially steeper hit so a free but
261				// underpowered route does not outrank an in-band option purely on cost.
262				penalty := float64(cand.MinPower-cand.Power) * belowMinPowerPenalty
263				base -= penalty
264				add("power", -penalty)
265			}
266			if cand.MaxPower > 0 && cand.Power > cand.MaxPower {
267				penalty := float64(cand.Power - cand.MaxPower)
268				base -= penalty
269				add("power", -penalty)
270			}
271		}
272		if cand.Power > 0 && cand.CostUSDPer1kTokens > 0 {
273			costPenalty := cand.CostUSDPer1kTokens * 500
274			if costPenalty > 60 {
275				costPenalty = 60
276			}
277			base -= costPenalty
278			add("cost", -costPenalty)
279		}
280		if cand.Power > 0 && cand.CostUSDPer1kTokens == 0 && candidateWithinPowerBounds(cand) {
281			switch {
282			case cand.CostClass == "local":
283				base += 15
284				add("cost", 15)
285			case cand.IsSubscription && cand.QuotaOK && !cand.QuotaStale && cand.QuotaPercentUsed < 80:
286				base += 15
287				add("quota_health", 15)
288			}
289		}
290		if cand.Power >= 9 && cand.IsSubscription && candidateWithinPowerBounds(cand) && cand.QuotaOK && !cand.QuotaStale && cand.QuotaPercentUsed < 80 {
291			base += 20
292			add("power", 20)
293		}
294	
295		// Context headroom is a ranking signal for otherwise eligible candidates.
296		// A larger spare window gives the model more room for completion and tool
297		// overhead, so reward it modestly without overpowering the primary policy.
298		if cand.ContextHeadroom > 0 {
299			headroomBonus := float64(cand.ContextHeadroom) / 1000.0
300			if headroomBonus > 30 {
301				headroomBonus = 30
302			}
303			base += headroomBonus
304			add("context_headroom", headroomBonus)
305		}
306	
307		// Observation-derived perf bias.
308		havePerfSignal := false
309		if cand.ObservedTokensPerSec > 0 {
310			// Small additive bonus, scaled.
311			bonus := cand.ObservedTokensPerSec / 100.0
312			base += bonus
313			add("performance", bonus)
314			havePerfSignal = true
315		}
316		if cand.ObservedLatencyMS > 0 {
317			// Latency is a tiebreaker-scale signal: faster endpoints gain a small
318			// bonus while very slow endpoints receive little benefit.
319			bonus := 1000.0 / cand.ObservedLatencyMS
320			base += bonus
321			add("performance", bonus)
322			havePerfSignal = true
323		}
324		if !havePerfSignal {
325			// Missing performance data is deliberate and mildly penalized rather
326			// than treated as a hidden zero-value bonus.
327			base -= unknownPerformancePenalty
328			add("performance", -unknownPerformancePenalty)
329		}
330		if cand.CostClass == "experimental" {
331			base -= 75
332			add("deployment_locality", -75)
333		}
334	
335		// base tracks the implicit profile baseline so the components sum to the
336		// same total as scorePolicy's legacy behavior.
337		components["base"] = base - (components["cost"] + components["deployment_locality"] + components["quota_health"] + components["sticky_affinity"] + components["utilization"] + components["power"] + components["context_headroom"] + components["performance"])
338		return components
339	}
