341	func quotaPressurePenalty(percentUsed int) float64 {
342		if percentUsed <= 0 {
343			return 0
344		}
345		penalty := float64(percentUsed) * 0.5
346		if percentUsed > 50 {
347			penalty += float64(percentUsed-50) * 1.5
348		}
349		if percentUsed > 80 {
350			penalty += float64(percentUsed-80) * 3
351		}
352		return penalty
353	}
