154	func routeCandidatesFromInternal(candidates []routing.Candidate, powerPolicy RoutePowerPolicy) []RouteCandidate {
155		if len(candidates) == 0 {
156			return nil
157		}
158		out := make([]RouteCandidate, len(candidates))
