165	func routeCandidateFromInternal(candidate routing.Candidate, powerPolicy RoutePowerPolicy) RouteCandidate {
166		components := RouteCandidateComponents{
167			Power:            candidate.Power,
168			Cost:             candidate.CostUSDPer1kTokens,
169			CostClass:        candidate.CostClass,
170			LatencyMS:        candidate.LatencyMS,
171			SpeedTPS:         candidate.SpeedTPS,
172			Utilization:      candidate.Utilization,
173			SuccessRate:      candidate.SuccessRate,
174			QuotaOK:          candidate.QuotaOK,
175			QuotaPercentUsed: candidate.QuotaPercentUsed,
176			QuotaTrend:       candidate.QuotaTrend,
177			Capability:       capabilityScoreForCostClass(candidate.CostClass),
178			ContextHeadroom:  candidate.ContextHeadroom,
179			StickyAffinity:   candidate.StickyAffinity,
180		}
181		powerHintFit := scorePowerHintFit(candidate.Power, powerPolicy)
182		scorePower := candidate.ScoreComponents["power"]
183		scoreCost := candidate.ScoreComponents["cost"]
184		scorePerformance := candidate.ScoreComponents["performance"]
185		scoreLocality := candidate.ScoreComponents["deployment_locality"]
186		scoreQuota := candidate.ScoreComponents["quota_health"]
187		scoreUtilization := candidate.ScoreComponents["utilization"]
188		components.PowerHintFit = powerHintFit
189		components.PowerWeightedCapability = scorePower - powerHintFit + positiveScorePart(scoreCost)
190		components.LatencyWeight = positiveScorePart(scorePerformance)
191		components.StaleSignalPenalty = positiveScorePart(-scorePerformance)
192		components.PlacementBonus = scoreLocality + candidate.StickyAffinity
193		components.QuotaBonus = positiveScorePart(scoreQuota)
194		components.MarginalCostPenalty = positiveScorePart(-scoreCost)
195		components.AvailabilityPenalty = positiveScorePart(-scoreQuota) + positiveScorePart(-scoreUtilization)
196		return RouteCandidate{
197			Harness:             candidate.Harness,
198			Provider:            candidate.Provider,
199			Billing:             candidate.Billing,
200			ActualCashSpend:     candidate.ActualCashSpend,
201			Endpoint:            candidate.Endpoint,
202			ServerInstance:      candidate.ServerInstance,
203			Model:               candidate.Model,
204			Score:               candidate.Score,
205			CostUSDPer1kTokens:  candidate.CostUSDPer1kTokens,
206			CostSource:          candidate.CostSource,
207			EffectiveCost:       candidate.CostUSDPer1kTokens,
208			EffectiveCostSource: candidate.CostSource,
209			Eligible:            candidate.Eligible,
210			Reason:              candidate.Reason,
211			FilterReason:        publicFilterReason(candidate),
212			ContextLength:       candidate.ContextLength,
213			ContextSource:       candidate.ContextSource,
214			Components:          components,
215		}
216	}
217	
218	func scorePowerHintFit(power int, policy RoutePowerPolicy) float64 {
219		if power <= 0 {
220			return 0
221		}
222		if policy.MinPower > 0 && power < policy.MinPower {
223			// Mirror the engine scorer: materially underpowered routes should not
224			// win just because they are cheap.
225			return -float64(policy.MinPower-power) * 12
226		}
227		if policy.MaxPower > 0 && power > policy.MaxPower {
228			return -float64(power - policy.MaxPower)
229		}
230		return 0
231	}
232	
233	func positiveScorePart(v float64) float64 {
234		if v > 0 {
235			return v
236		}
237		return 0
238	}
